import{c as t,Q as n,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Externalization in LLM Agents: A Unified Review of Memory, Skills, Protocols and Harness Engineering","description":"","frontmatter":{"title":"Externalization in LLM Agents: A Unified Review of Memory, Skills, Protocols and Harness Engineering","authors":"Chenyu Zhou, Huacan Chai, Wenteng Chen, et al. (20 authors)","published":"2026-04-09T00:00:00.000Z","source":"https://arxiv.org/abs/2604.08224"},"headers":[],"relativePath":"research/papers/2026-04-09-externalization-llm-agents-2604-08224.md","filePath":"research/papers/2026-04-09-externalization-llm-agents-2604-08224.md","lastUpdated":1779901665000}'),s={name:"research/papers/2026-04-09-externalization-llm-agents-2604-08224.md"};function i(o,e,l,c,d,p){return n(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="externalization-in-llm-agents-a-unified-review-of-memory-skills-protocols-and-harness-engineering" tabindex="-1">Externalization in LLM Agents: A Unified Review of Memory, Skills, Protocols and Harness Engineering <a class="header-anchor" href="#externalization-in-llm-agents-a-unified-review-of-memory-skills-protocols-and-harness-engineering" aria-label="Permalink to &quot;Externalization in LLM Agents: A Unified Review of Memory, Skills, Protocols and Harness Engineering&quot;">​</a></h1><p><strong>Authors</strong>: Chenyu Zhou, Huacan Chai, Wenteng Chen, et al. (20 authors) <strong>Published</strong>: April 9, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.08224" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.08224</a><strong>arXiv ID</strong>: 2604.08224 <strong>Categories</strong>: cs.AI, cs.LG, cs.MA</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>The paper argues that LLM agent progress increasingly depends on <strong>externalization</strong>—relocating cognitive burdens from model parameters into persistent external infrastructure (memory, skills, protocols, harness). This mirrors human cognitive history: just as writing transformed recall into recognition, agent infrastructure transforms hard internal tasks into forms models handle more reliably.</p><blockquote><p>&quot;Infrastructure matters because it transforms hard cognitive burdens into forms the model can solve more reliably.&quot;</p></blockquote><hr><h2 id="memory-externalizing-state-across-time" tabindex="-1">Memory: Externalizing State Across Time <a class="header-anchor" href="#memory-externalizing-state-across-time" aria-label="Permalink to &quot;Memory: Externalizing State Across Time&quot;">​</a></h2><p>Memory externalizes state across time through four components:</p><ul><li><strong>Working context</strong>: Active session information within the context window</li><li><strong>Episodic experience</strong>: Records of past interactions and their outcomes</li><li><strong>Semantic knowledge</strong>: Structured factual and procedural knowledge bases</li><li><strong>Personalized memory</strong>: User-specific preferences and behavioral patterns</li></ul><p>Architecture evolution trajectory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Monolithic context</span></span>
<span class="line"><span>    → Retrieval stores (RAG, vector DBs)</span></span>
<span class="line"><span>        → Hierarchical systems (tiered by recency/importance)</span></span>
<span class="line"><span>            → Adaptive architectures (dynamic load/evict based on task)</span></span></code></pre></div><p>Key tensions:</p><ul><li><strong>Recency vs relevance</strong>: Recent information is not always most relevant; retrieval strategies must balance both</li><li><strong>Compression fidelity</strong>: Summarization loses nuance; raw storage is token-expensive</li><li><strong>Cross-session continuity</strong>: Episodic memory degrades without active consolidation mechanisms (see Memory Survey 2603.07670: removing reflection → 48h behavioral degradation)</li></ul><hr><h2 id="skills-externalizing-procedural-expertise" tabindex="-1">Skills: Externalizing Procedural Expertise <a class="header-anchor" href="#skills-externalizing-procedural-expertise" aria-label="Permalink to &quot;Skills: Externalizing Procedural Expertise&quot;">​</a></h2><p>Skills externalize procedural expertise through specification, discovery, and composition. Four development stages:</p><ol><li><strong>Atomic execution primitives</strong>: Single-action tools (bash, read, write)</li><li><strong>Packaged expertise</strong>: Multi-step workflows authored as skills (SKILL.md pattern)</li><li><strong>Distilled capability</strong>: Skills learned from successful trajectories</li><li><strong>Composed ensembles</strong>: Skills that invoke other skills hierarchically</li></ol><p>Skill governance gap identified: most systems have skill creation mechanisms but lack lifecycle management for deprecated or contradictory skills.</p><p>Protocol for skill quality: skill descriptions must be precise enough to distinguish them from adjacent skills; ambiguous descriptions cause selection errors under tool competition.</p><hr><h2 id="protocols-externalizing-interaction-structure" tabindex="-1">Protocols: Externalizing Interaction Structure <a class="header-anchor" href="#protocols-externalizing-interaction-structure" aria-label="Permalink to &quot;Protocols: Externalizing Interaction Structure&quot;">​</a></h2><p>Protocols externalize interaction structure through machine-readable contracts:</p><ul><li><strong>Agent-tool protocols</strong>: JSON Schema tool calling (OpenAI FC, Anthropic Tool Use), MCP</li><li><strong>Agent-agent protocols</strong>: A2A (Google), structured handoff formats</li><li><strong>Agent-user protocols</strong>: Permission prompts, approval flows, audit trails</li></ul><p>Protocol standardization pressure: MCP vs A2A competitive dynamics, but open standards enable cross-harness portability that proprietary protocols cannot.</p><p>Critical insight: poorly specified protocols are as damaging as no protocols—ambiguous tool schemas produce the same accuracy collapse as missing tools (see TSCG paper 2605.04107 for empirical evidence: Phi-4 14B drops to 0% on malformed schemas).</p><hr><h2 id="harness-engineering-the-unification-layer" tabindex="-1">Harness Engineering: The Unification Layer <a class="header-anchor" href="#harness-engineering-the-unification-layer" aria-label="Permalink to &quot;Harness Engineering: The Unification Layer&quot;">​</a></h2><p>Harness is the runtime layer that unifies Memory, Skills, and Protocols:</p><h3 id="five-harness-functions" tabindex="-1">Five Harness Functions <a class="header-anchor" href="#five-harness-functions" aria-label="Permalink to &quot;Five Harness Functions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Orchestration</strong></td><td>Coordinates agent subcomponents and tool dispatch</td><td>subagent-strategy.md dispatch table</td></tr><tr><td><strong>Sandboxing</strong></td><td>Isolates execution from environment damage</td><td>Docker integration, path restrictions</td></tr><tr><td><strong>Observability</strong></td><td>Tracks component performance and execution traces</td><td>healthcheck.sh, session retros</td></tr><tr><td><strong>Governance</strong></td><td>Enforces permission policies and safety constraints</td><td>PreToolUse hooks, CLAUDE.md rules</td></tr><tr><td><strong>Context Budget Management</strong></td><td>Controls token allocation across the window</td><td>compact triggers, tool output limits</td></tr></tbody></table><h3 id="_98-4-infrastructure-ratio" tabindex="-1">98.4% Infrastructure Ratio <a class="header-anchor" href="#_98-4-infrastructure-ratio" aria-label="Permalink to &quot;98.4% Infrastructure Ratio&quot;">​</a></h3><p>Empirical analysis of Claude Code v2.1.88 (cross-referenced with 2604.14228):</p><ul><li><strong>98.4%</strong> of production codebase = operational infrastructure (context management, routing, recovery)</li><li><strong>1.6%</strong> = AI reasoning logic (actual model calls)</li><li>Implication: harness engineering quality determines agent success more than model capability selection</li></ul><h3 id="context-engineering-vs-prompt-engineering" tabindex="-1">Context Engineering vs Prompt Engineering <a class="header-anchor" href="#context-engineering-vs-prompt-engineering" aria-label="Permalink to &quot;Context Engineering vs Prompt Engineering&quot;">​</a></h3><blockquote><p>&quot;Context Engineering = filling the context window with just the right information for the next step&quot; (Karpathy 2025)</p></blockquote><p>The paper frames Context Engineering as the operationalization of externalization—deciding which external components (memory, skills, protocol schemas) to load at which moment. This is system architecture, not prompt crafting.</p><hr><h2 id="parametric-vs-external-capability-tradeoff" tabindex="-1">Parametric vs External Capability Tradeoff <a class="header-anchor" href="#parametric-vs-external-capability-tradeoff" aria-label="Permalink to &quot;Parametric vs External Capability Tradeoff&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>Parametric (in-weights)</th><th>External (in-harness)</th></tr></thead><tbody><tr><td><strong>Access cost</strong></td><td>Zero (always available)</td><td>Token budget</td></tr><tr><td><strong>Update cost</strong></td><td>Fine-tuning (expensive)</td><td>File edit (cheap)</td></tr><tr><td><strong>Specificity</strong></td><td>General</td><td>Task-specific</td></tr><tr><td><strong>Governance</strong></td><td>Opaque</td><td>Auditable</td></tr><tr><td><strong>Failure mode</strong></td><td>Hallucination</td><td>Loading error</td></tr></tbody></table><p>Key finding: for domain-specific tasks, external capability consistently outperforms equivalent parametric capability. A well-designed harness enables Haiku-class models to reach Sonnet-class quality on structured tasks.</p><hr><h2 id="governance-challenges" tabindex="-1">Governance Challenges <a class="header-anchor" href="#governance-challenges" aria-label="Permalink to &quot;Governance Challenges&quot;">​</a></h2><p>Three governance challenges identified across all four dimensions:</p><ol><li><strong>Ownership ambiguity</strong>: In multi-tenant environments, &quot;who owns externalized knowledge?&quot; is a security question, not just an organizational one</li><li><strong>Skill lifecycle management</strong>: Most systems create skills but lack deprecation, versioning, or conflict resolution</li><li><strong>Protocol lock-in</strong>: Early protocol adoption creates migration debt; open standards reduce but don&#39;t eliminate this</li></ol><hr><h2 id="four-dimension-unified-framework" tabindex="-1">Four-Dimension Unified Framework <a class="header-anchor" href="#four-dimension-unified-framework" aria-label="Permalink to &quot;Four-Dimension Unified Framework&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌─────────────────────────────────┐</span></span>
<span class="line"><span>                    │         HARNESS LAYER            │</span></span>
<span class="line"><span>                    │  (orchestration, sandbox, govern) │</span></span>
<span class="line"><span>                    └──────────────┬──────────────────┘</span></span>
<span class="line"><span>                                   │ unifies</span></span>
<span class="line"><span>           ┌───────────────────────┼───────────────────────┐</span></span>
<span class="line"><span>           ▼                       ▼                       ▼</span></span>
<span class="line"><span>    ┌─────────────┐       ┌─────────────────┐     ┌─────────────────┐</span></span>
<span class="line"><span>    │   MEMORY    │       │     SKILLS      │     │   PROTOCOLS     │</span></span>
<span class="line"><span>    │ (state/time)│       │  (procedural    │     │  (interaction   │</span></span>
<span class="line"><span>    │             │       │   expertise)    │     │   structure)    │</span></span>
<span class="line"><span>    └─────────────┘       └─────────────────┘     └─────────────────┘</span></span></code></pre></div><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Framework Concept</th><th>cc-workspace Implementation</th><th>Alignment</th></tr></thead><tbody><tr><td>Memory externalization</td><td><code>schemas/progress.schema.json</code> + Auto Memory</td><td>✅</td></tr><tr><td>Skills externalization</td><td><code>.claude/skills/</code> + SKILL.md pattern</td><td>✅</td></tr><tr><td>Protocol externalization</td><td>MCP servers + <code>settings.json</code> permissions</td><td>✅</td></tr><tr><td>Harness as unification</td><td><code>subagent-strategy.md</code> + harness-design rules</td><td>✅</td></tr><tr><td>Context budget management</td><td>compact triggers + tool output limits</td><td>✅</td></tr><tr><td>Skill lifecycle management</td><td>Missing deprecation/versioning mechanism</td><td>⚠️ Gap</td></tr><tr><td>Observability (structured)</td><td>healthcheck.sh = static, not semantic trace</td><td>⚠️ Gap</td></tr></tbody></table><hr><h2 id="key-citation" tabindex="-1">Key Citation <a class="header-anchor" href="#key-citation" aria-label="Permalink to &quot;Key Citation&quot;">​</a></h2><blockquote><p>&quot;Infrastructure matters because it transforms hard cognitive burdens into forms the model can solve more reliably.&quot; (arXiv:2604.08224)</p></blockquote><p>Integration targets: <code>research/agent-harness/FRAMEWORK.md</code> §理論基礎 + <code>ANTHROPIC-ALIGNMENT.md</code> §二映射表</p>`,55)])])}const u=t(s,[["render",i]]);export{g as __pageData,u as default};
